export enum AnalysisType {
  YOUTUBE = 'youtube',
  PDF = 'pdf',
  RESUME = 'resume'
}

export interface AnalysisResult {
  summary: string;
  scores: {
    clarity: number;
    engagement: number;
    originality: number;
    structure: number;
    overall: number;
  };
  improvements: string[];
  tips: {
    thumbnails?: string;
    titles?: string;
    content?: string;
    formatting?: string;
  };
  sources?: Array<{
    title: string;
    uri: string;
  }>;
}

export interface ThemeContextType {
  isDarkMode: boolean;
  toggleTheme: () => void;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AnalysisType, AnalysisResult } from "../types";

const API_KEY = process.env.API_KEY || "";

export const analyzeContent = async (
  type: AnalysisType,
  input: string | { data: string; mimeType: string },
  context: string = ""
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const systemInstructions = {
    [AnalysisType.YOUTUBE]: "You are a world-class YouTube strategist. Analyze the provided video link/context. Provide a quality score (0-100), a summary, and actionable advice for improving views, thumbnails, and engagement.",
    [AnalysisType.PDF]: "You are a professional document analyst. Summarize the content of the provided PDF and provide detailed scores on clarity, structure, and depth.",
    [AnalysisType.RESUME]: "You are a high-level technical recruiter. Score this resume against industry standards. Provide specific tips to improve the resume for ATS systems and human readability."
  };

  const schema = {
    type: Type.OBJECT,
    properties: {
      summary: { type: Type.STRING, description: "A concise summary of the content." },
      scores: {
        type: Type.OBJECT,
        properties: {
          clarity: { type: Type.NUMBER },
          engagement: { type: Type.NUMBER },
          originality: { type: Type.NUMBER },
          structure: { type: Type.NUMBER },
          overall: { type: Type.NUMBER }
        },
        required: ["clarity", "engagement", "originality", "structure", "overall"]
      },
      improvements: {
        type: Type.ARRAY,
        items: { type: Type.STRING }
      },
      tips: {
        type: Type.OBJECT,
        properties: {
          thumbnails: { type: Type.STRING },
          titles: { type: Type.STRING },
          content: { type: Type.STRING },
          formatting: { type: Type.STRING }
        }
      }
    },
    required: ["summary", "scores", "improvements", "tips"]
  };

  const isFile = typeof input !== 'string';
  const contents: any = isFile 
    ? { parts: [{ inlineData: input }, { text: `Analyze this content and context: ${context}` }] }
    : `Analyze this YouTube video link: ${input}. Search for its details if needed. ${context}`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      systemInstruction: systemInstructions[type],
      responseMimeType: "application/json",
      responseSchema: schema,
      tools: type === AnalysisType.YOUTUBE ? [{ googleSearch: {} }] : []
    }
  });

  try {
    const result = JSON.parse(response.text);
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
      result.sources = response.candidates[0].groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web.title,
          uri: chunk.web.uri
        }));
    }
    return result;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Invalid response format from AI");
  }
};

import React, { useState, useEffect } from 'react';
import { AnalysisType } from './types';
import Header from './components/Header';
import Hero from './components/Hero';
import Pricing from './components/Pricing';
import Contact from './components/Contact';
import Analyzer from './components/Analyzer';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [currentView, setCurrentView] = useState<'home' | 'analyzer'>('home');
  const [selectedType, setSelectedType] = useState<AnalysisType>(AnalysisType.YOUTUBE);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      document.body.classList.add('bg-[#0F172A]', 'text-slate-100');
      document.body.classList.remove('bg-slate-50', 'text-slate-900');
    } else {
      document.documentElement.classList.remove('dark');
      document.body.classList.add('bg-slate-50', 'text-slate-900');
      document.body.classList.remove('bg-[#0F172A]', 'text-slate-100');
    }
  }, [isDarkMode]);

  const navigateToAnalyzer = (type: AnalysisType) => {
    setSelectedType(type);
    setCurrentView('analyzer');
    window.scrollTo(0, 0);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header 
        isDarkMode={isDarkMode} 
        toggleTheme={() => setIsDarkMode(!isDarkMode)} 
        onHomeClick={() => setCurrentView('home')}
      />

      <main className="flex-grow pt-20">
        {currentView === 'home' ? (
          <>
            <Hero onStartClick={() => navigateToAnalyzer(AnalysisType.YOUTUBE)} />

            <section id="features" className="py-24 px-6 max-w-7xl mx-auto">
              <h2 className="text-4xl md:text-5xl font-bold text-center mb-16">
                Powerful <span className="text-violet-500">Analysis Features</span>
              </h2>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                <ToolPreviewCard 
                  icon={<YoutubeIcon />}
                  title="Youtube Analysis"
                  description="Analyze any YouTube video for engagement, clarity, and content structure."
                  onClick={() => navigateToAnalyzer(AnalysisType.YOUTUBE)}
                />
                <ToolPreviewCard 
                  icon={<FileIcon />}
                  title="PDF Analysis"
                  description="Upload documents and get instant quality assessments and suggestions."
                  onClick={() => navigateToAnalyzer(AnalysisType.PDF)}
                />
                <ToolPreviewCard 
                  icon={<ResumeIcon />}
                  title="Resume Scoring"
                  description="Get industry-standard scores and actionable tips to land your dream job."
                  onClick={() => navigateToAnalyzer(AnalysisType.RESUME)}
                />
              </div>
            </section>

            <Pricing />
            <Contact />
          </>
        ) : (
          <Analyzer 
            initialType={selectedType} 
            onBack={() => setCurrentView('home')} 
          />
        )}
      </main>

      <Footer />
