import React, { useState, useRef } from 'react';
import { AnalysisType, AnalysisResult } from '../types';
import { analyzeContent } from '../services/geminiService';
import AnalysisResultView from './AnalysisResultView';

interface AnalyzerProps {
  initialType: AnalysisType;
  onBack: () => void;
}

const Analyzer: React.FC<AnalyzerProps> = ({ initialType, onBack }) => {
  const [type, setType] = useState<AnalysisType>(initialType);
  const [input, setInput] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError('');
    }
  };

  const startAnalysis = async () => {
    setIsAnalyzing(true);
    setError('');
    setResult(null);

    try {
      let analysisResult: AnalysisResult;

      if (type === AnalysisType.YOUTUBE) {
        if (!input.includes('youtube.com') && !input.includes('youtu.be')) {
          throw new Error('Please enter a valid YouTube URL');
        }
        analysisResult = await analyzeContent(type, input);
      } else {
        if (!file) {
          throw new Error('Please upload a file first');
        }

        const base64Data = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = () => {
            const result = reader.result as string;
            resolve(result.split(',')[1]);
          };
          reader.readAsDataURL(file);
        });

        analysisResult = await analyzeContent(type, {
          data: base64Data,
          mimeType: file.type
        });
      }

      setResult(analysisResult);
    } catch (err: any) {
      setError(err.message || 'An error occurred during analysis');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-6 py-12">
      <button 
        onClick={onBack}
        className="flex items-center gap-2 text-slate-400 hover:text-white mb-8 transition-colors group"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="group-hover:-translate-x-1 transition-transform"><path d="m15 18-6-6 6-6"/></svg>
        Back to Dashboard
      </button>

      <div className="glass p-1 rounded-3xl mb-12 flex">
        {[
          { id: AnalysisType.YOUTUBE, label: 'YouTube' },
          { id: AnalysisType.PDF, label: 'Document' },
          { id: AnalysisType.RESUME, label: 'Resume' }
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => { setType(tab.id as AnalysisType); setFile(null); setInput(''); setError(''); }}
            className={`flex-1 py-4 rounded-2xl font-bold transition-all ${
              type === tab.id ? 'bg-violet-600 text-white shadow-lg' : 'hover:bg-white/5 text-slate-400'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      <div className="glass p-10 rounded-[2.5rem] border border-white/5 shadow-2xl">
        <h2 className="text-3xl font-black mb-8 flex items-center gap-3">
          <span className="w-2 h-8 bg-violet-600 rounded-full"></span>
          Analyze {type === AnalysisType.YOUTUBE ? 'Video' : type === AnalysisType.PDF ? 'Document' : 'Resume'}
        </h2>

        {type === AnalysisType.YOUTUBE ? (
          <div className="space-y-6">
            <div className="relative">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Paste YouTube Link Here..."
                className="w-full bg-slate-800/50 border border-white/10 rounded-2xl px-6 py-5 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all font-mono"
              />
              <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg>
              </div>
            </div>
            <p className="text-slate-400 text-sm">Example: https://www.youtube.com/watch?v=dQw4w9WgXcQ</p>
          </div>
        ) : (
          <div className="space-y-6">
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`border-2 border-dashed rounded-[2rem] p-12 text-center cursor-pointer transition-all ${
                file ? 'border-violet-500 bg-violet-500/5' : 'border-white/10 hover:border-violet-500/50 hover:bg-white/5'
              }`}
            >
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept={type === AnalysisType.PDF ? ".pdf" : ".pdf,.docx,.doc"}
              />
              <div className="w-20 h-20 bg-violet-500/10 rounded-3xl flex items-center justify-center mx-auto mb-6 text-violet-500">
                <svg xmlns="http://www.w3.org/2000/svg" width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" x2="12" y1="3" y2="15"/></svg>
              </div>
              <h3 className="text-xl font-bold mb-2">
                {file ? file.name : `Drop your ${type === AnalysisType.PDF ? 'PDF' : 'Resume'} here`}
              </h3>
              <p className="text-slate-400">or click to browse from computer</p>
            </div>
          </div>
        )}

        {error && (
          <div className="mt-6 p-4 bg-red-500/10 border border-red-500/20 text-red-400 rounded-xl flex items-center gap-3">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12" y1="8" y2="12"/><line x1="12" x2="12.01" y1="16" y2="16"/></svg>
            {error}
          </div>
        )}

        <button 
          onClick={startAnalysis}
          disabled={isAnalyzing || (type === AnalysisType.YOUTUBE ? !input : !file)}
          className="w-full mt-10 py-5 bg-violet-600 hover:bg-violet-700 disabled:opacity-50 disabled:cursor-not-allowed text-white font-black text-xl rounded-2xl shadow-xl shadow-violet-500/20 transition-all active:scale-95 flex items-center justify-center gap-3"
        >
          {isAnalyzing ? (
            <>
              <svg className="animate-spin h-6 w-6 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              CALCULATING IQ...
            </>
          ) : (
            <>
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m21 16-4 4-4-4"/><path d="M17 20V4"/><path d="m3 8 4-4 4 4"/><path d="M7 4v16"/></svg>
              START ANALYSIS
            </>
          )}
        </button>
      </div>

      {result && <AnalysisResultView result={result} type={type} />}
    </div>
  );
};

export default Analyzer;

