const ScoreCard: React.FC<{ label: string; score: number; color: string }> = ({ label, score, color }) => {
  const colorMap: any = {
    violet: 'text-violet-500',
    cyan: 'text-cyan-500',
    emerald: 'text-emerald-500',
    purple: 'text-purple-500'
  };

  const bgMap: any = {
