import React, { useState, useRef } from 'react';
import { AnalysisType, AnalysisResult } from '../types';
import { analyzeContent } from '../services/geminiService';
import AnalysisResultView from './AnalysisResultView';

interface AnalyzerProps {
  initialType: AnalysisType;
}

const Analyzer: React.FC<AnalyzerProps> = ({ initialType }) => {
  const [type, setType] = useState<AnalysisType>(initialType);
  const [input, setInput] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError('');
    }
  };

  const startAnalysis = async () => {
    setIsAnalyzing(true);
    setError('');
    setResult(null);

    try {
      let analysisResult: AnalysisResult;

      if (type === AnalysisType.YOUTUBE) {
        if (!input.trim()) throw new Error('Input required');
        if (!input.includes('youtube.com') && !input.includes('youtu.be')) {
          throw new Error('Please enter a valid YouTube URL');
        }
        analysisResult = await analyzeContent(type, input);
      } else {
        if (!file) throw new Error('Please upload a file first');

        const base64Data = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = () => {
            const res = reader.result as string;
            resolve(res.split(',')[1]);
          };
          reader.readAsDataURL(file);
        });

        analysisResult = await analyzeContent(type, {
          data: base64Data,
          mimeType: file.type
        });
      }

      setResult(analysisResult);
    } catch (err: any) {
      setError(err.message || 'An error occurred during analysis');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-6">
      <div className="glass p-1.5 rounded-2xl mb-8 flex border border-white/10 shadow-inner">
        {[
          { id: AnalysisType.YOUTUBE, label: 'YouTube Analysis' },
          { id: AnalysisType.PDF, label: 'Document Scan' },
          { id: AnalysisType.RESUME, label: 'Resume Score' }
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => { setType(tab.id as AnalysisType); setFile(null); setInput(''); setError(''); setResult(null); }}
            className={`flex-1 py-3.5 rounded-xl font-black uppercase text-xs tracking-widest transition-all ${
              type === tab.id 
                ? 'bg-violet-600 text-white shadow-[0_0_20px_rgba(139,92,246,0.4)]' 
                : 'hover:bg-white/5 text-slate-500'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      <div className="glass p-8 md:p-12 rounded-[2.5rem] border border-white/10 shadow-2xl relative overflow-hidden group">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-violet-500 to-transparent opacity-50"></div>

        <h2 className="text-3xl font-black mb-10 flex items-center gap-4 uppercase tracking-tighter">
          <span className="w-3 h-10 bg-violet-600 rounded-sm shadow-[0_0_15px_rgba(139,92,246,0.6)]"></span>
          Analyze {type === AnalysisType.YOUTUBE ? 'Video' : type === AnalysisType.PDF ? 'Document' : 'Resume'}
        </h2>

        {type === AnalysisType.YOUTUBE ? (
          <div className="space-y-6">
            <div className="relative group">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="INPUT YOUTUBE COMMAND (LINK)..."
                className="w-full bg-slate-900/80 border border-white/10 rounded-2xl px-6 py-6 focus:outline-none focus:ring-2 focus:ring-violet-500 focus:border-transparent transition-all font-mono text-lg tracking-tight"
              />
              <div className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-violet-500 transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`border-2 border-dashed rounded-[2.5rem] p-16 text-center cursor-pointer transition-all ${
                file ? 'border-violet-500 bg-violet-500/10' : 'border-white/10 hover:border-violet-500/50 hover:bg-white/5'
              }`}
            >
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept={type === AnalysisType.PDF ? ".pdf" : ".pdf,.docx,.doc"}
              />
              <div className="w-24 h-24 bg-violet-500/10 rounded-3xl flex items-center justify-center mx-auto mb-8 text-violet-500 shadow-inner">
                <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" x2="12" y1="3" y2="15"/></svg>
              </div>
              <h3 className="text-2xl font-black mb-3 uppercase tracking-tighter">
                {file ? file.name : `UPLOAD SOURCE FILE`}
              </h3>
              <p className="text-slate-500 font-medium tracking-wide">CLICK TO BROWSE LOCAL DIRECTORY</p>
            </div>
          </div>
        )}

        {error && (
          <div className="mt-8 p-5 bg-red-500/10 border border-red-500/30 text-red-400 rounded-2xl flex items-center gap-4 font-bold animate-pulse">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12" y1="8" y2="12"/><line x1="12" x2="12.01" y1="16" y2="16"/></svg>
            SYSTEM ERROR: {error}
          </div>
        )}

        <button 
          onClick={startAnalysis}
          disabled={isAnalyzing || (type === AnalysisType.YOUTUBE ? !input : !file)}
          className="w-full mt-12 py-6 bg-violet-600 hover:bg-violet-700 disabled:opacity-30 disabled:cursor-not-allowed text-white font-black text-2xl rounded-2xl shadow-[0_10px_40px_rgba(139,92,246,0.3)] transition-all active:scale-95 flex items-center justify-center gap-4 uppercase tracking-tighter"
        >
          {isAnalyzing ? (
            <>
              <svg className="animate-spin h-8 w-8 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              PROCESSING DATA...
            </>
          ) : (
            <>
              <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v4"/><path d="m4.93 4.93 2.83 2.83"/><path d="M2 12h4"/><path d="m4.93 19.07 2.83-2.83"/><path d="M12 22v-4"/><path d="m19.07 19.07-2.83-2.83"/><path d="M22 12h-4"/><path d="m19.07 4.93-2.83 2.83"/></svg>
              EXECUTE ANALYSIS
            </>
          )}
        </button>
      </div>

      {result && <AnalysisResultView result={result} type={type} />}
    </div>
  );
};

export default Analyzer;

