import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AnalysisType, AnalysisResult } from "../types";

const API_KEY = process.env.API_KEY || "";

const extractYoutubeId = (url: string): string | null => {
  const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*/;
  const match = url.match(regExp);
  return (match && match[7].length === 11) ? match[7] : null;
};

export const analyzeContent = async (
  type: AnalysisType,
  input: string | { data: string; mimeType: string },
  context: string = ""
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const systemInstructions = {
    [AnalysisType.YOUTUBE]: "You are a world-class YouTube strategist and SEO expert. Analyze the provided video link. Extract the existing tags used in the video (if searchable) or suggest what tags are likely being used/should be used. Provide a quality score (0-100), a summary, and actionable advice specifically for: 1. Thumbnail visual appeal 2. Title CTR optimization 3. Tag SEO 4. Overall engagement.",
    [AnalysisType.PDF]: "You are a professional document analyst. Summarize the content of the provided PDF and provide detailed scores on clarity, structure, and depth.",
    [AnalysisType.RESUME]: "You are a high-level technical recruiter. Score this resume against industry standards. Provide specific tips to improve the resume for ATS systems and human readability."
  };

  const schema = {
    type: Type.OBJECT,
    properties: {
      summary: { type: Type.STRING, description: "A concise summary of the content." },
      tags: { 
        type: Type.ARRAY, 
        items: { type: Type.STRING },
        description: "List of existing or highly relevant SEO tags for this content." 
      },
      scores: {
        type: Type.OBJECT,
        properties: {
          clarity: { type: Type.NUMBER },
          engagement: { type: Type.NUMBER },
          originality: { type: Type.NUMBER },
          structure: { type: Type.NUMBER },
          overall: { type: Type.NUMBER }
        },
        required: ["clarity", "engagement", "originality", "structure", "overall"]
      },
      improvements: {
        type: Type.ARRAY,
        items: { type: Type.STRING }
      },
      tips: {
        type: Type.OBJECT,
        properties: {
          thumbnails: { type: Type.STRING, description: "Specific critique and improvement for the thumbnail." },
          titles: { type: Type.STRING, description: "Critique and better alternatives for the title." },
          tags: { type: Type.STRING, description: "How to improve tag strategy for search." },
          content: { type: Type.STRING },
          formatting: { type: Type.STRING }
        }
      }
    },
    required: ["summary", "scores", "improvements", "tips"]
  };

  const isFile = typeof input !== 'string';
  const contents: any = isFile 
    ? { parts: [{ inlineData: input }, { text: `Analyze this content and context: ${context}` }] }
    : `Analyze this YouTube video link: ${input}. Search for its details including tags and metadata. ${context}`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      systemInstruction: systemInstructions[type],
      responseMimeType: "application/json",
      responseSchema: schema,
      tools: type === AnalysisType.YOUTUBE ? [{ googleSearch: {} }] : []
    }
  });

  try {
    const result = JSON.parse(response.text);

    // Supplement with thumbnail URL if it's a YouTube video
    if (type === AnalysisType.YOUTUBE && typeof input === 'string') {
      const videoId = extractYoutubeId(input);
      if (videoId) {
        result.thumbnailUrl = `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`;
      }
    }

    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
      result.sources = response.candidates[0].groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web.title,
          uri: chunk.web.uri
        }));
    }
    return result;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Invalid response format from AI");
  }
};

