import React, { useState, useRef } from 'react';
import { AnalysisType, AnalysisResult } from '../types';
import { analyzeContent } from '../services/geminiService';
import AnalysisResultView from './AnalysisResultView';

interface AnalyzerProps {
  initialType: AnalysisType;
}

const Analyzer: React.FC<AnalyzerProps> = ({ initialType }) => {
  const [type, setType] = useState<AnalysisType>(initialType);
  const [input, setInput] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError('');
    }
  };

  const startAnalysis = async () => {
    setIsAnalyzing(true);
    setError('');
    setResult(null);

    try {
      let analysisResult: AnalysisResult;

      if (type === AnalysisType.YOUTUBE) {
        if (!input.trim()) throw new Error('COMMAND INPUT REQUIRED');
        if (!input.includes('youtube.com') && !input.includes('youtu.be')) {
          throw new Error('INVALID TARGET URL: TARGET MUST BE YOUTUBE');
        }
        analysisResult = await analyzeContent(type, input);
      } else {
        if (!file) throw new Error('SOURCE FILE MISSING: UPLOAD PDF/RESUME');

        const base64Data = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = () => {
            const res = reader.result as string;
            resolve(res.split(',')[1]);
          };
          reader.readAsDataURL(file);
        });

        analysisResult = await analyzeContent(type, {
          data: base64Data,
          mimeType: file.type
        });
      }

      setResult(analysisResult);
    } catch (err: any) {
      setError(err.message || 'SYSTEM COMPROMISED: ANALYSIS FAILED');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-6">
      {/* TAB SYSTEM */}
      <div className="glass p-1.5 rounded-[1.5rem] mb-8 flex border border-white/10 shadow-inner max-w-2xl mx-auto">
        {[
          { id: AnalysisType.YOUTUBE, label: 'YouTube' },
          { id: AnalysisType.PDF, label: 'Document' },
          { id: AnalysisType.RESUME, label: 'Resume' }
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => { setType(tab.id as AnalysisType); setFile(null); setInput(''); setError(''); setResult(null); }}
            className={`flex-1 py-3 rounded-xl font-black uppercase text-[10px] tracking-[0.2em] transition-all duration-300 ${
              type === tab.id 
                ? 'bg-violet-600 text-white shadow-[0_5px_15px_rgba(139,92,246,0.3)] scale-[1.02]' 
                : 'hover:bg-white/5 text-slate-500'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* INPUT CARD */}
      <div className="glass p-8 md:p-14 rounded-[3rem] border border-white/10 shadow-2xl relative overflow-hidden group">
        <div className="absolute top-0 left-0 w-full h-[2px] bg-gradient-to-r from-transparent via-violet-500/50 to-transparent"></div>

        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
          <div>
            <h2 className="text-4xl font-black uppercase tracking-tighter mb-2">
              <span className="text-violet-500 italic">Target</span> Selection
            </h2>
            <p className="text-slate-500 font-bold text-xs uppercase tracking-widest">Initialization: {type === AnalysisType.YOUTUBE ? 'Video Feed' : type === AnalysisType.PDF ? 'Document Buffer' : 'Career Profile'}</p>
          </div>
          <div className="flex items-center gap-2">
            <span className="w-1.5 h-1.5 bg-violet-500 rounded-full animate-pulse"></span>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">System Ready</span>
          </div>
        </div>

        {type === AnalysisType.YOUTUBE ? (
          <div className="space-y-6">
            <div className="relative group">
              <div className="absolute -inset-1 bg-gradient-to-r from-violet-600 to-indigo-600 rounded-3xl blur opacity-10 group-focus-within:opacity-20 transition duration-500"></div>
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="INPUT DATA LINK (HTTPS://WWW.YOUTUBE.COM/...)"
                className="relative w-full bg-slate-900/90 border border-white/10 rounded-2xl px-7 py-7 focus:outline-none focus:border-violet-500/50 transition-all font-mono text-lg tracking-tight placeholder:text-slate-700"
              />
              <div className="absolute right-7 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-violet-500 transition-colors pointer-events-none">
                <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div 
