              <p className="text-slate-500 font-bold uppercase text-[10px] tracking-[0.2em]">{file ? 'FILE LOADED INTO BUFFER' : 'DRAG & DROP OR BROWSE DIRECTORY'}</p>
            </div>
          </div>
