        {error && (
          <div className="mt-8 p-5 bg-red-500/5 border border-red-500/20 text-red-400 rounded-2xl flex items-center gap-4 font-bold animate-pulse text-xs uppercase tracking-widest">
            <div className="w-2 h-2 bg-red-500 rounded-full"></div>
            ERROR: {error}
          </div>
        )}

        <button 
          onClick={startAnalysis}
          disabled={isAnalyzing || (type === AnalysisType.YOUTUBE ? !input : !file)}
          className="w-full mt-12 py-7 bg-violet-600 hover:bg-violet-700 disabled:opacity-20 disabled:cursor-not-allowed text-white font-black text-2xl rounded-[1.8rem] shadow-[0_15px_40px_rgba(139,92,246,0.25)] transition-all active:scale-[0.98] flex items-center justify-center gap-5 uppercase tracking-tighter group/btn"
        >
          {isAnalyzing ? (
            <>
              <svg className="animate-spin h-8 w-8 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
