            { id: AnalysisType.PDF_REFINE, label: 'Refine' },
            { id: AnalysisType.RESUME, label: 'Resume' },
            { id: AnalysisType.PDF, label: 'Doc' }
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => { setType(tab.id as AnalysisType); setFile(null); setInput(''); setInstructions(''); setResult(null); }}
              className={`flex-1 min-w-[100px] py-3 rounded-xl font-black uppercase text-[10px] tracking-[0.2em] transition-all ${
                type === tab.id 
                  ? 'bg-violet-600 text-white shadow-[0_5px_15px_rgba(139,92,246,0.3)]' 
                  : 'hover:bg-white/5 text-slate-500'
              }`}
            >
