            </button>
          ))}
        </div>

        <div className="glass p-8 md:p-12 rounded-[2.5rem] border border-white/10 shadow-2xl relative overflow-hidden">
          <h2 className="text-3xl font-black uppercase tracking-tighter mb-8 flex items-center gap-3">
            <span className="w-1.5 h-6 bg-violet-600 rounded-full"></span>
