                  onChange={(e) => setInput(e.target.value)}
                  placeholder={type === AnalysisType.YOUTUBE ? "HTTPS://WWW.YOUTUBE.COM/..." : "CYBERPUNK CITYSCAPE, NEON LIGHTING, 8K..."}
                  className="w-full bg-slate-900/90 border border-white/10 rounded-2xl px-6 py-5 focus:outline-none focus:border-violet-500/50 font-mono text-sm tracking-tight"
