import { HistoryItem } from '../types';

/**
 * World-class Drive Service for Neural Storage.
 * Note: Real implementation requires valid ClientID and API Key from Google Console.
 * This service provides the structural architecture for Google Drive Persistence.
 */

const FOLDER_NAME = 'ContentIQ_Archive';

export class GoogleDriveService {
  private static accessToken: string | null = null;

  static setToken(token: string) {
    this.accessToken = token;
  }

  static async syncToDrive(item: HistoryItem) {
    if (!this.accessToken) return;

    try {
      // 1. Check if folder exists, if not create it
      const folderId = await this.getOrCreateFolder();

      // 2. Upload history item as a JSON file
      const fileMetadata = {
        name: `CIQ_LOG_${item.id}.json`,
        parents: [folderId],
        mimeType: 'application/json'
      };

      const fileContent = JSON.stringify(item);
      const boundary = '-------314159265358979323846';
      const delimiter = "\r\n--" + boundary + "\r\n";
      const close_delim = "\r\n--" + boundary + "--";

      const multipartRequestBody =
          delimiter +
          'Content-Type: application/json\r\n\r\n' +
          JSON.stringify(fileMetadata) +
          delimiter +
          'Content-Type: application/json\r\n\r\n' +
          fileContent +
          close_delim;

      await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.accessToken}`,
          'Content-Type': `multipart/related; boundary=${boundary}`
        },
        body: multipartRequestBody
      });

      console.log(`[Neural Sync] Log ${item.id} persisted to Google Drive.`);
    } catch (error) {
      console.error('[Drive Service Error]', error);
    }
  }

  private static async getOrCreateFolder(): Promise<string> {
    const query = `name = '${FOLDER_NAME}' and mimeType = 'application/vnd.google-apps.folder' and trashed = false`;
    const response = await fetch(`https://www.googleapis.com/drive/v3/files?q=${encodeURIComponent(query)}`, {
      headers: { 'Authorization': `Bearer ${this.accessToken}` }
    });
    const data = await response.json();

    if (data.files && data.files.length > 0) {
      return data.files[0].id;
    }

    // Create folder if not found
    const createResponse = await fetch('https://www.googleapis.com/drive/v3/files', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.accessToken}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        name: FOLDER_NAME,
        mimeType: 'application/vnd.google-apps.folder'
      })
    });
    const folder = await createResponse.json();
    return folder.id;
  }

  static async fetchHistoryFromDrive(): Promise<HistoryItem[]> {
    if (!this.accessToken) return [];

    try {
      const folderId = await this.getOrCreateFolder();
      const query = `'${folderId}' in parents and trashed = false`;
      const response = await fetch(`https://www.googleapis.com/drive/v3/files?q=${encodeURIComponent(query)}&fields=files(id, name)`, {
        headers: { 'Authorization': `Bearer ${this.accessToken}` }
      });
      const data = await response.json();

      const history: HistoryItem[] = [];
      for (const file of data.files || []) {
        if (file.name.startsWith('CIQ_LOG_')) {
          const contentResp = await fetch(`https://www.googleapis.com/drive/v3/files/${file.id}?alt=media`, {
            headers: { 'Authorization': `Bearer ${this.accessToken}` }
          });
          const item = await contentResp.json();
          history.push(item);
        }
      }
      return history.sort((a, b) => b.timestamp - a.timestamp);
    } catch (e) {
      return [];
    }
  }
}

import React, { useState, useEffect } from 'react';
import { AnalysisType, HistoryItem, User } from './types';
import Header from './components/Header';
import Hero from './components/Hero';
import Analyzer from './components/Analyzer';
import Footer from './components/Footer';
import { GoogleDriveService } from './services/googleDriveService';

const App: React.FC = () => {
  const [user, setUser] = useState<User>({
    name: '',
    email: '',
    picture: '',
    isLoggedIn: false,
    accessToken: ''
  });
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    // Load local cache initially for speed
    const savedHistory = localStorage.getItem('ciq_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedUser = localStorage.getItem('ciq_user');
    if (savedUser) {
      const parsed = JSON.parse(savedUser);
      setUser(parsed);
      if (parsed.accessToken) {
        GoogleDriveService.setToken(parsed.accessToken);
        syncFromDrive();
      }
    }
  }, []);

  const syncFromDrive = async () => {
    setIsSyncing(true);
    const driveData = await GoogleDriveService.fetchHistoryFromDrive();
    if (driveData.length > 0) {
      setHistory(driveData);
      localStorage.setItem('ciq_history', JSON.stringify(driveData));
    }
    setIsSyncing(false);
  };

  const saveToHistory = async (item: HistoryItem) => {
    // Update local state
    const newHistory = [item, ...history].slice(0, 50);
    setHistory(newHistory);
    localStorage.setItem('ciq_history', JSON.stringify(newHistory));

    // Persist to Google Drive if logged in
    if (user.isLoggedIn) {
      setIsSyncing(true);
      await GoogleDriveService.syncToDrive(item);
      setIsSyncing(false);
    }
  };

  const handleLogin = () => {
    /** 
     * World-class OAuth Simulation. 
     * In production, this triggers the standard Google Identity popup.
     */
    const mockToken = 'G-DRIVE-AUTH-' + Math.random().toString(36).substring(7);
    const mockUser: User = {
      name: 'Neural Operator',
      email: 'user@gmail.com',
      picture: `https://api.dicebear.com/7.x/bottts/svg?seed=${Date.now()}`,
      isLoggedIn: true,
      accessToken: mockToken
    };

    setUser(mockUser);
    GoogleDriveService.setToken(mockToken);
    localStorage.setItem('ciq_user', JSON.stringify(mockUser));
    syncFromDrive();
  };

  const handleLogout = () => {
    setUser({ name: '', email: '', picture: '', isLoggedIn: false, accessToken: '' });
    localStorage.removeItem('ciq_user');
    setHistory([]);
  };

  return (
    <div className="min-h-screen flex flex-col relative">
      <Header 
        user={user} 
        onLogin={handleLogin} 
        onLogout={handleLogout} 
        isSyncing={isSyncing}
      />

      <main className="flex-grow">
        {!user.isLoggedIn ? (
          <Hero onStartClick={handleLogin} />
        ) : (
          <section className="py-24 px-6 max-w-[1440px] mx-auto">
            <div className="flex items-center justify-between mb-12">
              <div>
                <h2 className="text-5xl font-black uppercase tracking-tighter">Neural <span className="text-violet-500">Suite</span></h2>
                <div className="flex items-center gap-3 mt-2">
                  <div className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-amber-500 animate-pulse' : 'bg-emerald-500'}`}></div>
                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
                    {isSyncing ? 'Synchronizing with Google Drive...' : 'Google Drive: Connected & Synced'}
                  </span>
                </div>
              </div>

              <div className="flex gap-4">
                 <div className="px-5 py-3 glass rounded-2xl border border-white/5 flex flex-col items-center">
                    <span className="text-[9px] font-black text-slate-500 uppercase mb-1">Total Logs</span>
                    <span className="text-xl font-black">{history.length}</span>
                 </div>
              </div>
            </div>

            <Analyzer 
              onResultSaved={saveToHistory} 
              history={history} 
              onClearHistory={() => setHistory([])} 
            />
          </section>
        )}
      </main>

      <Footer />
    </div>
  );
};

export default App;

