import React, { useState, useEffect } from 'react';
import { AnalysisType, HistoryItem, User } from './types';
import Header from './components/Header';
import Hero from './components/Hero';
import Analyzer from './components/Analyzer';
import Footer from './components/Footer';
import { GoogleDriveService } from './services/googleDriveService';

const App: React.FC = () => {
  const [user, setUser] = useState<User>({
    name: '',
    email: '',
    picture: '',
    isLoggedIn: false,
    accessToken: ''
  });
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    // Load local cache initially for speed
    const savedHistory = localStorage.getItem('ciq_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedUser = localStorage.getItem('ciq_user');
    if (savedUser) {
      const parsed = JSON.parse(savedUser);
      setUser(parsed);
      if (parsed.accessToken) {
        GoogleDriveService.setToken(parsed.accessToken);
        syncFromDrive();
      }
    }
  }, []);

  const syncFromDrive = async () => {
    setIsSyncing(true);
    const driveData = await GoogleDriveService.fetchHistoryFromDrive();
    if (driveData.length > 0) {
      setHistory(driveData);
      localStorage.setItem('ciq_history', JSON.stringify(driveData));
    }
    setIsSyncing(false);
  };

  const saveToHistory = async (item: HistoryItem) => {
    // Update local state
    const newHistory = [item, ...history].slice(0, 50);
    setHistory(newHistory);
    localStorage.setItem('ciq_history', JSON.stringify(newHistory));

    // Persist to Google Drive if logged in
    if (user.isLoggedIn) {
      setIsSyncing(true);
      await GoogleDriveService.syncToDrive(item);
      setIsSyncing(false);
    }
  };

  const handleLogin = () => {
    /** 
     * World-class OAuth Simulation. 
     */
    const mockToken = 'G-DRIVE-AUTH-' + Math.random().toString(36).substring(7);
    const mockUser: User = {
      name: 'Neural Operator',
      email: 'user@gmail.com',
      picture: `https://api.dicebear.com/7.x/bottts/svg?seed=${Date.now()}`,
      isLoggedIn: true,
      accessToken: mockToken
    };

    setUser(mockUser);
    GoogleDriveService.setToken(mockToken);
    localStorage.setItem('ciq_user', JSON.stringify(mockUser));
    syncFromDrive();
  };

  const handleLogout = () => {
    setUser({ name: '', email: '', picture: '', isLoggedIn: false, accessToken: '' });
    localStorage.removeItem('ciq_user');
    setHistory([]);
  };

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
      const offset = 100; // Account for fixed header
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - offset;
      window.scrollTo({
        top: offsetPosition,
        behavior: "smooth"
      });
    }
  };

  return (
    <div className="min-h-screen flex flex-col relative">
      <Header 
        user={user} 
        onLogin={handleLogin} 
        onLogout={handleLogout} 
        isSyncing={isSyncing}
        onNavigate={scrollToSection}
      />

      <main className="flex-grow">
        {!user.isLoggedIn ? (
          <Hero onStartClick={handleLogin} />
        ) : (
          <section id="workspace-section" className="py-24 px-6 max-w-[1440px] mx-auto">
            <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-12 gap-6">
              <div>
                <h2 className="text-5xl font-black uppercase tracking-tighter">Neural <span className="text-violet-500">Suite</span></h2>
                <div className="flex items-center gap-3 mt-2">
                  <div className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-amber-500 animate-pulse' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]'}`}></div>
                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
                    {isSyncing ? 'Synchronizing with Google Drive...' : 'Google Drive: Connected & Synced'}
                  </span>
                </div>
              </div>

              <div className="flex gap-4">
                 <div className="px-6 py-3 glass rounded-2xl border border-white/5 flex flex-col items-center min-w-[120px]">
                    <span className="text-[9px] font-black text-slate-500 uppercase mb-1">Neural Buffer</span>
                    <span className="text-xl font-black">{history.length} <span className="text-xs text-slate-600">/ 50</span></span>
                 </div>
              </div>
            </div>

            <Analyzer 
              onResultSaved={saveToHistory} 
              history={history} 
              onClearHistory={() => {
                setHistory([]);
                localStorage.removeItem('ciq_history');
              }} 
            />
          </section>
        )}

        <section id="features-section" className="py-20 border-t border-white/5 bg-slate-950/50">
           <div className="max-w-7xl mx-auto px-6">
              <div className="text-center mb-16">
                 <h3 className="text-[10px] font-black text-violet-500 uppercase tracking-[0.4em] mb-4">Protocol Modules</h3>
                 <h2 className="text-4xl font-black uppercase tracking-tighter">High Performance <span className="text-slate-500">Capabilities</span></h2>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                 <CapabilityCard title="Visual Intelligence" desc="Gemini-2.5-Flash Image generation for high-fidelity assets." icon="🎨" />
                 <CapabilityCard title="Strategic Audit" desc="Deep YouTube analysis with Google Search grounding." icon="📺" />
                 <CapabilityCard title="Neural Storage" desc="Automatic sync to ContentIQ_Archive on Google Drive." icon="☁️" />
              </div>
           </div>
        </section>
      </main>

      <Footer />
    </div>
  );
};

const CapabilityCard = ({ title, desc, icon }: { title: string; desc: string; icon: string }) => (
  <div className="glass p-8 rounded-[2rem] border border-white/5 hover:border-violet-500/20 transition-all group">
    <div className="text-4xl mb-6 group-hover:scale-110 transition-transform">{icon}</div>
    <h4 className="text-lg font-black uppercase mb-3 tracking-tight">{title}</h4>
    <p className="text-slate-400 text-sm leading-relaxed">{desc}</p>
  </div>
);

export default App;

